1	type Cell = [number, number]; // [x, y]
2	
3	const toKey = ([x, y]: Cell): string => `${x},${y}`;
4	const fromKey = (key: string): Cell => {
5	  const [x, y] = key.split(",").map(Number);
6	  return [x, y];
7	};
8	
9	const NEIGHBOR_OFFSETS: Cell[] = [
10	  [-1, -1], [0, -1], [1, -1],
11	  [-1, 0], [1, 0],
12	  [-1, 1], [0, 1], [1, 1],
13	];
14	
15	const isAliveNextGeneration = (alive: boolean, neighbors: number): boolean =>
16	  neighbors === 3 || (alive && neighbors === 2);
17	
18	const countLiveNeighbors = (cells: Cell[]): Map<string, number> => {
19	  const counts = new Map<string, number>();
20	  for (const [x, y] of cells) {
21	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
22	      const neighborKey = toKey([x + dx, y + dy]);
23	      counts.set(neighborKey, (counts.get(neighborKey) ?? 0) + 1);
24	    }
25	  }
26	  return counts;
27	};
28	
29	export function nextGeneration(cells: Cell[]): Cell[] {
30	  const living = new Set(cells.map(toKey));
31	
32	  return [...countLiveNeighbors(cells)]
33	    .filter(([key, count]) => isAliveNextGeneration(living.has(key), count))
34	    .map(([key]) => fromKey(key));
35	}
